import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep = (step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!formData.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!formData.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(formData.email)) {
        newErrors.email = 'Please enter a valid email';
      }
    }

    if (step === 2 && formData.satisfaction === 0) {
      newErrors.satisfaction = 'Please select a satisfaction rating';
    }

    if (step === 3 && formData.features.length === 0) {
      newErrors.features = 'Please select at least one feature';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = (): void => {
    if (validateStep(currentStep)) {
      if (currentStep < 5) {
        setCurrentStep((prev) => (prev + 1) as 1 | 2 | 3 | 4 | 5);
      }
    }
  };

  const handleBack = (): void => {
    if (currentStep > 1) {
      setCurrentStep((prev) => (prev - 1) as 1 | 2 | 3 | 4 | 5);
      setErrors({});
    }
  };

  const handleSubmit = (): void => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  const isStep1Valid = formData.name.trim() && isValidEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const isStep3Valid = formData.features.length > 0;
  const isStep4Valid = true; // Comments are optional

  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label,
  }));

  const featureOptions = props.featureOptions.map((feature) => ({
    label: feature,
    checked: formData.features.includes(feature),
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Customer Feedback Survey</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
        </Stack>

        {/* Progress Bar */}
        <Progress
          value={currentStep === 5 ? 100 : (currentStep / 4) * 100}
          max={100}
          size="md"
          variant="default"
        />

        {/* Step 1: Name and Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={formData.name}
                onChange={(value) => {
                  setFormData({ ...formData, name: value });
                  if (errors.name) setErrors({ ...errors, name: '' });
                }}
                error={errors.name}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => {
                  setFormData({ ...formData, email: value });
                  if (errors.email) setErrors({ ...errors, email: '' });
                }}
                error={errors.email}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you with our service?"
                value={String(formData.satisfaction)}
                onChange={(value) => {
                  setFormData({ ...formData, satisfaction: parseInt(value, 10) });
                  if (errors.satisfaction) setErrors({ ...errors, satisfaction: '' });
                }}
                options={satisfactionOptions.map((opt, idx) => ({
                  value: String(idx + 1),
                  label: opt.label,
                }))}
                direction="vertical"
                error={errors.satisfaction}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Features of Interest</Heading>
              <Text color="var(--ggui-color-onSurfaceVariant)" size="sm">
                Which features are you most interested in?
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={formData.features.includes(feature)}
                    onChange={(checked) => {
                      const newFeatures = checked
                        ? [...formData.features, feature]
                        : formData.features.filter((f) => f !== feature);
                      setFormData({ ...formData, features: newFeatures });
                      if (errors.features) setErrors({ ...errors, features: '' });
                    }}
                  />
                ))}
              </Stack>
              {errors.features && (
                <Text color="var(--ggui-color-error-500)" size="sm">
                  {errors.features}
                </Text>
              )}
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Your feedback (optional)"
                placeholder="Tell us what you think..."
                value={formData.comments}
                onChange={(value) => {
                  if (value.length <= 500) {
                    setFormData({ ...formData, comments: value });
                  }
                }}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Stack gap="var(--ggui-spacing-3)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Name</Text>
                    <Text>{formData.name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Email</Text>
                    <Text>{formData.email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Satisfaction Rating</Text>
                    <Text>{props.satisfactionLabels[formData.satisfaction - 1]}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Features of Interest</Text>
                    <Stack gap="var(--ggui-spacing-1)">
                      {formData.features.length > 0 ? (
                        formData.features.map((feature) => (
                          <Badge key={feature} variant="primary" size="sm">
                            {feature}
                          </Badge>
                        ))
                      ) : (
                        <Text color="var(--ggui-color-onSurfaceVariant)" size="sm">
                          None selected
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Comments</Text>
                    <Text>
                      {formData.comments || '(No comments provided)'}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
            {currentStep < 5 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={
                  currentStep === 1
                    ? !isStep1Valid
                    : currentStep === 2
                      ? !isStep2Valid
                      : currentStep === 3
                        ? !isStep3Valid
                        : !isStep4Valid
                }
              >
                Next
              </Button>
            )}
            {currentStep === 5 && (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Row>
      </Stack>
    </Container>
  );
}

