// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State for search filter and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by name or symbol (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const q = searchQuery.toLowerCase();
    return props.elements.filter(
      (el) =>
        (el.name && el.name.toLowerCase().includes(q)) ||
        (el.symbol && el.symbol.toLowerCase().includes(q))
    );
  }, [searchQuery, props.elements]);

  // Build category color map using design tokens
  const getCategoryColor = useCallback((category?: string): string => {
    const categoryColors: Record<string, string> = {
      'noble-gas': 'var(--ggui-color-info-100)',
      'halogen': 'var(--ggui-color-warning-100)',
      'alkali-metal': 'var(--ggui-color-success-100)',
      'alkaline-earth-metal': 'var(--ggui-color-primary-100)',
      'nonmetal': 'var(--ggui-color-error-100)',
      'metalloid': 'var(--ggui-color-primary-50)',
      'transition-metal': 'var(--ggui-color-primary-200)',
      'lanthanide': 'var(--ggui-color-warning-50)',
      'actinide': 'var(--ggui-color-error-50)',
    };
    return categoryColors[category || ''] || 'var(--ggui-color-surfaceVariant)';
  }, []);

  // Get category text color (for contrast)
  const getCategoryTextColor = useCallback((category?: string): string => {
    const darkCategories = ['noble-gas', 'nonmetal'];
    return darkCategories.includes(category || '') ? 'var(--ggui-color-onSurface)' : 'var(--ggui-color-onSurfaceVariant)';
  }, []);

  // Get all unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  return (
    <Stack gap="var(--ggui-spacing-6)">
      {/* Search Bar */}
      <Stack gap="var(--ggui-spacing-3)">
        <Heading level={1}>Periodic Table of Elements</Heading>
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder="Search by element name or symbol..."
          size="md"
        />
      </Stack>

      {/* Legend */}
      <Card padding="var(--ggui-spacing-4)" shadow="sm">
        <Stack gap="var(--ggui-spacing-3)">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
            Category Legend
          </Text>
          <Row gap="var(--ggui-spacing-3)" wrap>
            {categories.map((cat) => (
              <Box
                key={cat}
                padding="var(--ggui-spacing-2)"
                paddingX="var(--ggui-spacing-3)"
                background={getCategoryColor(cat)}
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Text
                  variant="caption"
                  color={getCategoryTextColor(cat)}
                  weight="medium"
                >
                  {cat}
                </Text>
              </Box>
            ))}
          </Row>
        </Stack>
      </Card>

      {/* Periodic Table Grid */}
      <Box
        borderRadius="var(--ggui-shape-radius-lg)"
        padding="var(--ggui-spacing-4)"
        background="var(--ggui-color-surfaceVariant)"
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2)',
          minHeight: '600px',
        }}
      >
        {filteredElements.map((el) => {
          const rowStart = (el.row || 1) + 1; // +1 to account for header
          const colStart = el.col || 1;
          const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

          return (
            <Card
              key={el.atomicNumber}
              as={Clickable}
              onClick={() => setSelectedElement(el)}
              padding="var(--ggui-spacing-3)"
              shadow={isSelected ? 'md' : 'sm'}
              radius="md"
              border={isSelected}
              style={{
                gridRow: rowStart,
                gridColumn: colStart,
                background: getCategoryColor(el.category),
                cursor: 'pointer',
                transition: 'all 200ms ease-in-out',
                borderWidth: isSelected ? '2px' : '0px',
                borderColor: isSelected ? 'var(--ggui-color-primary-600)' : 'transparent',
                borderStyle: 'solid',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                minHeight: '80px',
              }}
              hoverStyle={{
                opacity: 0.85,
                transform: 'scale(1.05)',
              }}
            >
              {/* Atomic number (top-left) */}
              <Text
                variant="caption"
                size="xs"
                color={getCategoryTextColor(el.category)}
                align="left"
                style={{
                  position: 'absolute',
                  top: 'var(--ggui-spacing-2)',
                  left: 'var(--ggui-spacing-2)',
                  fontWeight: 'var(--ggui-font-weight-semibold)',
                }}
              >
                {el.atomicNumber}
              </Text>
              {/* Symbol (large, centered) */}
              <Text
                size="2xl"
                weight="bold"
                color={getCategoryTextColor(el.category)}
                align="center"
              >
                {el.symbol}
              </Text>
              {/* Name (small, below symbol) */}
              <Text
                variant="caption"
                size="xs"
                color={getCategoryTextColor(el.category)}
                align="center"
              >
                {el.name}
              </Text>
            </Card>
          );
        })}
      </Box>

      {/* Detail Panel */}
      {selectedElement && (
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  {selectedElement.category}
                </Text>
              </Stack>
              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                Close
              </Button>
            </Row>
            <Divider />
            <Row gap="var(--ggui-spacing-6)" wrap>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Symbol
                </Text>
                <Text size="xl" weight="bold">
                  {selectedElement.symbol}
                </Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Atomic Number
                </Text>
                <Text size="lg">{selectedElement.atomicNumber}</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Atomic Weight
                </Text>
                <Text size="lg">
                  {selectedElement.atomicWeight?.toFixed(2) || 'N/A'}
                </Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Position
                </Text>
                <Text size="lg">
                  Row {selectedElement.row}, Col {selectedElement.col}
                </Text>
              </Stack>
            </Row>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

