/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // Actions
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Helpers
  const isOutOfStock = !props.product.stock || props.product.stock === 0;
  const maxQuantity = props.product.stock || 1;
  const stockStatus = props.product.stock && props.product.stock >= 10 ? 'In Stock' : 'Low Stock';
  const stockBadgeVariant = props.product.stock && props.product.stock >= 10 ? 'success' : 'warning';

  // Render star rating
  const renderStars = (rating: number | undefined) => {
    const stars = [];
    const ratingValue = rating ?? 0;
    for (let i = 1; i <= 5; i++) {
      const isFilled = i <= ratingValue;
      const isPartial = i - ratingValue > 0 && i - ratingValue < 1;
      stars.push(
        <Icon
          key={i}
          name={isPartial ? 'star-half-2' : 'star'}
          size={18}
          color={isFilled || isPartial ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    }
    return stars;
  };

  // Handle quantity change
  const handleQuantityChange = (newQty: number) => {
    const clamped = Math.max(1, Math.min(newQty, maxQuantity));
    setQuantity(clamped);
  };

  // Handle add to cart
  const handleAddToCart = () => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  };

  // Format price
  const formattedPrice = props.product.price ? `${props.product.currency || '$'}${props.product.price.toFixed(2)}` : 'N/A';

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
