           {/* Product Image Placeholder */}
           <Box
             background="var(--ggui-color-primary-100)"
             borderRadius="var(--ggui-shape-radius-lg)"
             padding="var(--ggui-spacing-8)"
             style={{
               width: '100%',
               maxWidth: '400px',
               height: '400px',
               minHeight: '400px',
               display: 'flex',
               alignItems: 'center',
               justifyContent: 'center',
               flex: '0 1 100%',
             }}
             role="img"
             aria-label={`${props.product.name || 'Product'} image placeholder`}
           >
             <Stack align="center" gap="var(--ggui-spacing-4)">
               <Icon name="image" size={48} color="var(--ggui-color-primary-600)" />
               <Text variant="body" color="var(--ggui-color-primary-700)">
                 {props.product.name || 'Product Image'}
               </Text>
             </Stack>
           </Box>

          {/* Product Details */}
           <Stack gap="var(--ggui-spacing-4)" style={{ flex: '1 1 auto', minWidth: '0' }}>
            {/* Title */}
            <Heading level={1}>{props.product.name || 'Product Name'}</Heading>

            {/* Rating */}
             <Row gap="var(--ggui-spacing-2)" align="center" aria-label={`${props.product.rating ? props.product.rating.toFixed(1) : '0'} out of 5 stars`}>
               <Row gap="var(--ggui-spacing-1)" align="center" aria-hidden="true">
                 {renderStars(props.product.rating)}
               </Row>
               <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                 {props.product.rating ? `${props.product.rating.toFixed(1)}` : '0'} ({props.product.reviewCount || 0} reviews)
               </Text>
             </Row>

            {/* Price */}
            <Heading level={2} color="var(--ggui-color-primary-600)">
              {formattedPrice}
            </Heading>

            {/* Stock Status Badge */}
            <Badge variant={stockBadgeVariant}>{stockStatus}</Badge>
          </Stack>
        </Stack>

         <Spacer size={16} />
         <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />

        <Tabs
          variant="line"
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                 <Text variant="body" color="var(--ggui-color-onSurface)" is="div" style={{ whiteSpace: 'pre-wrap' }}>
                  {props.product.description || 'No description available.'}
                </Text>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Stack gap="var(--ggui-spacing-4)">
                  {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'key', header: 'Property' },
                        { key: 'value', header: 'Value' },
