                          return { key: String((spec as any).key), value: String((spec as any).value) };
                        }
                        return { key: 'unknown', value: 'unknown' };
                      })}
                      compact
                      striped
                    />
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      No specifications available.
                    </Text>
                  )}
                </Stack>
              ),
