                                     color={isFilled || isPartial ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                                   />
                                 );
                               })}
                             </Row>
                            <Text variant="body" color="var(--ggui-color-onSurface)">
                              {reviewObj.text || reviewObj.content || 'No review text.'}
                            </Text>
                          </Stack>
                        </Card>
                      );
                    })
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      No reviews available.
                    </Text>
                  )}
                </Stack>
              ),
            },
          ]}
          activeKey={activeTab}
          onChange={setActiveTab}
        />

        {/* Bottom Section: Quantity & Add to Cart */}
