                 <Row gap="var(--ggui-spacing-2)" align="center">
                   <Button
                     variant="outline"
                     size="sm"
                     onClick={() => handleQuantityChange(quantity - 1)}
                     disabled={quantity <= 1}
                     aria-label="Decrease quantity"
                   >
                     −
                   </Button>
                   <Text variant="body" align="center" style={{ minWidth: '40px' }} role="status" aria-live="polite">
                     {quantity}
                   </Text>
                   <Button
                     variant="outline"
