import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State for messages (initial from props, new ones from stream)
  const [allMessages, setAllMessages] = useState(props.messages);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest && message.latest.sender && message.latest.text && message.latest.timestamp) {
      setAllMessages(prev => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest && typing.latest.sender) {
      if (typing.latest.active) {
        setTypingUsers(prev => new Set([...prev, typing.latest.sender!]));
      } else {
        setTypingUsers(prev => {
          const updated = new Set(prev);
          updated.delete(typing.latest.sender!);
          return updated;
        });
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({
        text: inputValue,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  // Handle Enter key to send (Shift+Enter for newline would be handled by default)
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
    for (const msg of allMessages) {
      if (groups.length === 0 || groups[groups.length - 1].sender !== msg.sender) {
        groups.push({ sender: msg.sender, messages: [] });
      }
      groups[groups.length - 1].messages.push({ text: msg.text, timestamp: msg.timestamp });
    }
    return groups;
  }, [allMessages]);

  // Format timestamp to HH:MM
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
    } catch {
      return '';
    }
  };

  return (
    <Card padding="0" shadow="md" radius="lg" style={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
      {/* Header */}
      <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
        <Row justify="between" align="center">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Heading level={3} color="var(--ggui-color-primary-900)">{props.title}</Heading>
          </Stack>
          <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
        </Row>
      </Box>

      {/* Message List */}
      <Stack direction="vertical" gap="var(--ggui-spacing-3)" style={{ flex: 1, overflowY: 'auto', minHeight: '300px' }}>
        {groupedMessages.length === 0 ? (
          <Box style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '200px' }}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No messages yet. Start the conversation!</Text>
          </Box>
        ) : (
          groupedMessages.map((group, groupIdx) => {
            const isCurrentUser = group.sender === props.currentUser;
            return (
              <Stack key={`group-${groupIdx}`} gap="var(--ggui-spacing-2)" align={isCurrentUser ? 'end' : 'start'} style={{ alignItems: isCurrentUser ? 'flex-end' : 'flex-start' }}>
                {group.messages.map((msg, msgIdx) => (
                  <Box
                    key={`${groupIdx}-${msgIdx}`}
                    padding="var(--ggui-spacing-3)"
                    background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{ maxWidth: '70%', wordWrap: 'break-word' }}
                  >
                    <Text
                      variant="body"
                      color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                    >
                      {msg.text || ''}
                    </Text>
                    {msg.timestamp && (
                      <Text
                        variant="caption"
                        color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                        style={{ marginTop: 'var(--ggui-spacing-1)' }}
                      >
                        {formatTime(msg.timestamp)}
                      </Text>
                    )}
                  </Box>
                ))}
              </Stack>
            );
          })
        )}
        {/* Typing indicator */}
        {typingUsers.size > 0 && (
          <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center">
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing
            </Text>
            <Spinner size={16} color="var(--ggui-color-primary-600)" />
          </Stack>
        )}
        <div ref={messagesEndRef} />
      </Stack>

      {/* Input Area */}
       <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderTop: '1px solid var(--ggui-color-outline)' }}>
        <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="end">
          <TextArea
            label="Message"
            placeholder="Type your message..."
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            rows={3}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={!inputValue.trim()}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

