/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for displayed stocks (updated by stream events)
  const [displayedStocks, setDisplayedStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const updateTimerRef = useRef<NodeJS.Timeout | null>(null);

  // Merge stream updates into displayed stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setDisplayedStocks((prev) => {
        const updated = [...prev];
        const index = updated.findIndex((s) => s.symbol === update.symbol);
        if (index >= 0) {
          updated[index] = {
            ...updated[index],
            price: update.price ?? updated[index].price,
            change: update.change ?? updated[index].change,
            changePercent: update.changePercent ?? updated[index].changePercent,
          };
        }
        return updated;
      });
      setLastUpdated(new Date());
      if (update.symbol) {
        setHighlightedSymbols((prev) => new Set(prev).add(update.symbol));
        clearTimeout(updateTimerRef.current ?? undefined);
        updateTimerRef.current = setTimeout(() => {
          setHighlightedSymbols(new Set());
        }, 1000);
      }
    }
  }, [priceUpdate.latest]);

  const isMarketOpen = marketStatus.latest?.status === 'open';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with market status and title */}
