            </Badge>
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite">
            Last Updated: {lastUpdated ? lastUpdated.toLocaleTimeString() : 'Never'}
          </Text>
        </Stack>
        {/* Stock ticker list */}
        <Box as="section" role="region" aria-label="Stock ticker list">
          <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap="var(--ggui-spacing-6)">
          {displayedStocks.length === 0 ? (
            <Box padding="var(--ggui-spacing-6)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)" style={{ gridColumn: '1 / -1' }}>
              <Text align="center" color="var(--ggui-color-onSurfaceVariant)">No stocks available</Text>
            </Box>
          ) : (
            displayedStocks.map((stock) => {
              const isPositive = (stock.changePercent ?? 0) >= 0;
              const isHighlighted = highlightedSymbols.has(stock.symbol ?? '');
              const textColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
              const borderColor = isPositive ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';

                return (
                  <Card
                    key={stock.symbol}
                    padding="var(--ggui-spacing-4)"
                    shadow="md"
                    style={{
                      borderColor: borderColor,
                      borderWidth: '1px',
                      background: isHighlighted ? (isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)') : undefined,
                      animation: isHighlighted ? 'ggui-stock-flash 0.4s ease-out' : 'none',
                      transition: 'border-color 0.2s ease, box-shadow 0.2s ease',
                    }}
                    aria-label={`${stock.symbol}: ${stock.name}, Price: $${stock.price?.toFixed(2) ?? '0.00'}, Change: ${stock.change?.toFixed(2) ?? '0.00'} (${stock.changePercent?.toFixed(2) ?? '0.00'}%)`}
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      {/* Ticker symbol (large, bold) */}
                      <Heading level={3} color={textColor}>
                        {stock.symbol ?? 'N/A'}
                      </Heading>

                      {/* Company name */}
                      <Text variant="body" color="var(--ggui-color-onSurface)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>

                      {/* Current price */}
                      <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurface)">
                        ${stock.price?.toFixed(2) ?? '0.00'}
                      </Text>

                      {/* Change amount and percentage with arrow */}
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                        <span role="img" aria-label={isPositive ? 'increase' : 'decrease'}>
                          {isPositive ? '▲' : '▼'}
                        </span>
                        <Text variant="body" color={textColor} weight="semibold">
                          {stock.change !== undefined && stock.change >= 0 ? '+' : ''}
                          {stock.change?.toFixed(2) ?? '0.00'}
                        </Text>
                        <Text variant="caption" color={textColor} weight="semibold">
                          ({stock.changePercent !== undefined && stock.changePercent >= 0 ? '+' : ''}
                          {stock.changePercent?.toFixed(2) ?? '0.00'}%)
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                );
            })
          </CardGrid>
        </Box>
      </Stack>
    </Container>
  );


}

