          <Progress value={progressValue} max={100} size="md" variant="default" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {step === 1 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Profile Setup</Heading>
            <Input
              label="Name"
              placeholder="Enter your name"
