            />
            <Input
              label="Email"
              type="email"
              placeholder="you@example.com"
              value={email}
              onChange={setEmail}
              required
              error={email && !isEmailValid ? 'Please enter a valid email address' : email ? '' : 'Email is required'}
            />
            <RadioGroup
              label="Choose Avatar"
              value={avatar}
              onChange={setAvatar}
              options={props.avatarOptions.map((opt) => ({ value: opt, label: opt }))}
              direction="horizontal"
            />
          </Stack>
        )}

        {/* Step 2: Preferences */}
        {step === 2 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Preferences</Heading>
            <Select
              label="Role"
              value={role}
              onChange={setRole}
              options={props.roleOptions.map((r) => ({ value: r, label: r }))}
              placeholder="Select your role"
              required
              error={!role ? 'Role is required' : ''}
            />
            <Toggle
              label="Email Notifications"
              checked={emailNotifications}
              onChange={setEmailNotifications}
              size="md"
            />
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label">Theme Preference</Text>
              <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                <Card
                  as={Clickable}
                  onClick={() => setTheme('light')}
                  padding="var(--ggui-spacing-3)"
                  style={{
                    cursor: 'pointer',
                    borderWidth: theme === 'light' ? '2px' : '1px',
                    borderColor: theme === 'light' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                    backgroundColor: theme === 'light' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                  }}
                >
                  <Text variant="label">☀️ Light</Text>
                </Card>
                <Card
                  as={Clickable}
                  onClick={() => setTheme('dark')}
                  padding="var(--ggui-spacing-3)"
                  style={{
                    cursor: 'pointer',
                    borderWidth: theme === 'dark' ? '2px' : '1px',
                    borderColor: theme === 'dark' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                    backgroundColor: theme === 'dark' ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                  }}
                >
                  <Text variant="label">🌙 Dark</Text>
                </Card>
              </Stack>
            </Stack>
          </Stack>
        )}

        {/* Step 3: Review & Confirm */}
        {step === 3 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Review & Confirm</Heading>
            <Card padding="var(--ggui-spacing-4)" shadow="md">
              <Stack gap="var(--ggui-spacing-3)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-3)" align="center">
                  <Text variant="label">Avatar:</Text>
                  <Text size="lg">{avatar}</Text>
                </Stack>
                <Divider />
                <Stack gap="var(--ggui-spacing-2)">
                  <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                    <Text variant="label">Name:</Text>
                    <Text>{name}</Text>
                  </Stack>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                    <Text variant="label">Email:</Text>
                    <Text>{email}</Text>
                  </Stack>
                  <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                    <Text variant="label">Role:</Text>
                    <Text>{role}</Text>
                  </Stack>
                </Stack>
                <Divider />
                <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                  <Text variant="label">Email Notifications:</Text>
                  <Badge variant={emailNotifications ? 'success' : 'default'}>{emailNotifications ? 'Enabled' : 'Disabled'}</Badge>
                </Stack>
                <Stack direction="horizontal" gap="var(--ggui-spacing-3)">
                  <Text variant="label">Theme:</Text>
                  <Badge variant="primary">{theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Badge>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="ghost"
            onClick={handleBack}
            disabled={step === 1}
          >
            Go Back
          </Button>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)">
            {step < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={!isStep1Valid || (step === 2 && !isStep2Valid)}
              >
                Next
              </Button>
            )}
            {step === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}
